INSERT INTO examples (name, category, framework, files, dependencies, metadata) VALUES ('"get-the-next-and-previous-sibling-node-of-an-element"', '"Logic"', '"vanilla"', '{"demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      Get the next and previous sibling node of an element\r\n    </h1>\r\n    <ul>\r\n      <!-- The gray wizard -->\r\n      <li>Gandalf</li>\r\n      <li>Radagast</li>\r\n      <li id=\"hermione\">Hermione</li>\r\n      <!-- The surprise hero -->\r\n      <li>Neville</li>\r\n    </ul>\r\n\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n", "demo.js": "/**\n * Get the next and previous sibling node of an element,\n * including nodes that aren\u2019t elements (such as comments and text fragments).\n */\n\nlet hermione = document.querySelector(\"#hermione\");\n\n// returns <!-- The surprise hero -->\nlet next = hermione.nextSibling;\n\n// returns <li>Radagast</li>\nlet previous = hermione.previousSibling;\n\nconsole.warn(next);\nconsole.warn(previous);\n"}', '{}', '{"original_path": "Vanilla/Logic/DOM/traverse/get-the-next-and-previous-sibling-node-of-an-element"}'), ('"get-the-parent-of-an-element"', '"Logic"', '"vanilla"', '{"demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      Get the parent of an element\r\n    </h1>\r\n    <div id=\"app\">\r\n      <h1>Hello, world!</h1>\r\n    </div>\r\n\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n", "demo.js": "/**\n * Get the parent of an element.\n */\n\nlet h1 = document.querySelector(\"h1\");\n\n// returns the #app element\nlet parent = h1.parentNode;\n"}', '{}', '{"original_path": "Vanilla/Logic/DOM/traverse/get-the-parent-of-an-element"}'), ('"return-a-live-htmlcollection"', '"Logic"', '"vanilla"', '{"demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      Return a live HTMLcollection\r\n    </h1>\r\n    <div class=\"wizards\">\r\n      <ul>\r\n        <li>Gandalf</li>\r\n        <li>Radagast</li>\r\n        <li>Hermione</li>\r\n        <li>Neville</li>\r\n      </ul>\r\n    </div>\r\n\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n", "demo.js": "/**\n * Returns a live HTMLCollection,\n * which means if items are added to it later,\n * the collection updates as well.\n */\n\nlet wizards = document.querySelector(\".wizards\");\nlet wizardsList = document.querySelector(\".wizards ul\");\n\n// returns an HTMLCollection with the ul element\nlet wizardDescendants = wizards.children;\n\n// returns an HTMLCollection with the list items\nlet wizardListDescendants = wizardsList.children;\n\n// Add a new item\nlet li = document.createElement(\"li\");\nli.textContent = \"Merlin\";\nwizardsList.append(li);\n\n// wizardListDescendants now automatically contains the new li\n"}', '{}', '{"original_path": "Vanilla/Logic/DOM/traverse/return-a-live-htmlcollection"}'), ('"bouncing-loader"', '"Prsnt"', '"vanilla"', '{"demo.css": "@keyframes bouncing-loader {\n  to {\n    opacity: 0.1;\n    transform: translate3d(0, -16px, 0);\n  }\n}\n\n.bouncing-loader {\n  display: flex;\n  justify-content: center;\n}\n\n.bouncing-loader > div {\n  width: 16px;\n  height: 16px;\n  margin: 3rem 0.2rem;\n  background: #8385aa;\n  border-radius: 50%;\n  animation: bouncing-loader 0.6s infinite alternate;\n}\n\n.bouncing-loader > div:nth-child(2) {\n  animation-delay: 0.2s;\n}\n\n.bouncing-loader > div:nth-child(3) {\n  animation-delay: 0.4s;\n}\n", "demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      Bouncing loader\r\n    </h1>\r\n    <div class=\"bouncing-loader\">\r\n      <div></div>\r\n      <div></div>\r\n      <div></div>\r\n    </div>\r\n\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n"}', '{}', '{"original_path": "Vanilla/Prsnt/Animation/bouncing-loader"}'), ('"button-border-animation"', '"Prsnt"', '"vanilla"', '{"demo.css": ".animated-border-button {\n  background-color: #263059;\n  border: none;\n  color: #ffffff;\n  outline: none;\n  padding: 12px 40px 10px;\n  position: relative;\n}\n\n.animated-border-button::before,\n.animated-border-button::after {\n  border: 0 solid transparent;\n  transition: all 0.3s;\n  content: \"\";\n  height: 0;\n  position: absolute;\n  width: 24px;\n}\n\n.animated-border-button::before {\n  border-top: 2px solid #263059;\n  right: 0;\n  top: -4px;\n}\n\n.animated-border-button::after {\n  border-bottom: 2px solid #263059;\n  bottom: -4px;\n  left: 0;\n}\n\n.animated-border-button:hover::before,\n.animated-border-button:hover::after {\n  width: 100%;\n}\n", "demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      Button border animation\r\n    </h1>\r\n    <button class=\"animated-border-button\">Submit</button>\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n"}', '{}', '{"original_path": "Vanilla/Prsnt/Animation/button-border-animation"}'), ('"button-fill-animation"', '"Prsnt"', '"vanilla"', '{"demo.css": ".animated-fill-button {\n  padding: 20px;\n  background: #fff;\n  color: #000;\n  border: 1px solid #000;\n  cursor: pointer;\n  transition: 0.3s all ease-in-out;\n}\n\n.animated-fill-button:hover {\n  background: #000;\n  color: #fff;\n}\n", "demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      Button fill animation\r\n    </h1>\r\n    <button class=\"animated-fill-button\">Submit</button>\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n"}', '{}', '{"original_path": "Vanilla/Prsnt/Animation/button-fill-animation"}'), ('"button-grow-animation"', '"Prsnt"', '"vanilla"', '{"demo.css": ".button-grow {\n  color: #65b5f6;\n  background-color: transparent;\n  border: 1px solid #65b5f6;\n  border-radius: 4px;\n  padding: 0 16px;\n  cursor: pointer;\n  transition: all 0.3s ease-in-out;\n}\n\n.button-grow:hover {\n  transform: scale(1.1);\n}\n", "demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      Button grow animation\r\n    </h1>\r\n    <button class=\"button-grow\">Submit</button>\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n"}', '{}', '{"original_path": "Vanilla/Prsnt/Animation/button-grow-animation"}'), ('"button-shrink-animation"', '"Prsnt"', '"vanilla"', '{"demo.css": ".button-shrink {\n  color: #65b5f6;\n  background-color: transparent;\n  border: 1px solid #65b5f6;\n  border-radius: 4px;\n  padding: 0 16px;\n  cursor: pointer;\n  transition: all 0.3s ease-in-out;\n}\n\n.button-shrink:hover {\n  transform: scale(0.8);\n}\n", "demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      Button shrink animation\r\n    </h1>\r\n    <button class=\"button-shrink\">Submit</button>\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n"}', '{}', '{"original_path": "Vanilla/Prsnt/Animation/button-shrink-animation"}'), ('"button-swing-animation"', '"Prsnt"', '"vanilla"', '{"demo.css": ".button-swing {\n  color: #65b5f6;\n  background-color: transparent;\n  border: 1px solid #65b5f6;\n  border-radius: 4px;\n  padding: 0 16px;\n  cursor: pointer;\n  transition: all 0.2s ease-in-out;\n}\n\n.button-swing:focus {\n  animation: swing 1s ease;\n  animation-iteration-count: 1;\n}\n\n@keyframes swing {\n  15% {\n    transform: translateX(5px);\n  }\n  30% {\n    transform: translateX(-5px);\n  }\n  50% {\n    transform: translateX(3px);\n  }\n  65% {\n    transform: translateX(-3px);\n  }\n  80% {\n    transform: translateX(2px);\n  }\n  100% {\n    transform: translateX(0);\n  }\n}\n", "demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      Button swing animation\r\n    </h1>\r\n    <button class=\"button-swing\">Submit</button>\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n"}', '{}', '{"original_path": "Vanilla/Prsnt/Animation/button-swing-animation"}'), ('"donut-spinner"', '"Prsnt"', '"vanilla"', '{"demo.css": "@keyframes donut-spin {\n  0% {\n    transform: rotate(0deg);\n  }\n  100% {\n    transform: rotate(360deg);\n  }\n}\n\n.donut {\n  display: inline-block;\n  border: 4px solid rgba(0, 0, 0, 0.1);\n  border-left-color: #7983ff;\n  border-radius: 50%;\n  width: 30px;\n  height: 30px;\n  animation: donut-spin 1.2s linear infinite;\n}\n", "demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      Donut spinner\r\n    </h1>\r\n    <div class=\"donut\"></div>\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n"}', '{}', '{"original_path": "Vanilla/Prsnt/Animation/donut-spinner"}'), ('"hover-shadow-box-animation"', '"Prsnt"', '"vanilla"', '{"demo.css": ".hover-shadow-box-animation {\n  display: inline-block;\n  vertical-align: middle;\n  transform: perspective(1px) translateZ(0);\n  box-shadow: 0 0 1px transparent;\n  margin: 10px;\n  transition-duration: 0.3s;\n  transition-property: box-shadow, transform;\n}\n\n.hover-shadow-box-animation:hover,\n.hover-shadow-box-animation:focus,\n.hover-shadow-box-animation:active {\n  box-shadow: 1px 10px 10px -10px rgba(0, 0, 24, 0.5);\n  transform: scale(1.2);\n}\n", "demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      Hover shadow box animation\r\n    </h1>\r\n    <p class=\"hover-shadow-box-animation\">Box it!</p>\r\n\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n"}', '{}', '{"original_path": "Vanilla/Prsnt/Animation/hover-shadow-box-animation"}'), ('"hover-underline-animation"', '"Prsnt"', '"vanilla"', '{"demo.css": ".hover-underline-animation {\n  display: inline-block;\n  position: relative;\n  color: #0087ca;\n}\n\n.hover-underline-animation::after {\n  content: '''';\n  position: absolute;\n  width: 100%;\n  transform: scaleX(0);\n  height: 2px;\n  bottom: 0;\n  left: 0;\n  background-color: #0087ca;\n  transform-origin: bottom right;\n  transition: transform 0.25s ease-out;\n}\n\n.hover-underline-animation:hover::after {\n  transform: scaleX(1);\n  transform-origin: bottom left;\n}\n", "demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      Hover underline animation\r\n    </h1>\r\n    <p class=\"hover-underline-animation\">Hover this text to see the effect!</p>\r\n\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n"}', '{}', '{"original_path": "Vanilla/Prsnt/Animation/hover-underline-animation"}'), ('"image-rotate-on-hover"', '"Prsnt"', '"vanilla"', '{"demo.css": ".hover-rotate {\n  overflow: hidden;\n  margin: 8px;\n  min-width: 240px;\n  max-width: 320px;\n  width: 100%;\n}\n\n.hover-rotate img {\n  transition: all 0.3s;\n  box-sizing: border-box;\n  max-width: 100%;\n}\n\n.hover-rotate:hover img {\n  transform: scale(1.3) rotate(5deg);\n}\n", "demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      Image rotate on hover\r\n    </h1>\r\n    <figure class=\"hover-rotate\">\r\n      <img src=\"https://picsum.photos/id/669/600/800.jpg\" />\r\n    </figure>\r\n\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n"}', '{}', '{"original_path": "Vanilla/Prsnt/Animation/image-rotate-on-hover"}'), ('"perspective-transform-on-hover"', '"Prsnt"', '"vanilla"', '{"demo.css": ".image-card {\n  display: inline-block;\n  box-sizing: border-box;\n  margin: 1rem;\n  width: 240px;\n  height: 320px;\n  padding: 8px;\n  border-radius: 1rem;\n  background: url(\"https://picsum.photos/id/1049/240/320\");\n  box-shadow: rgba(0, 0, 0, 0.25) 0px 25px 50px -12px;\n}\n\n.perspective-left {\n  transform: perspective(1500px) rotateY(15deg);\n  transition: transform 1s ease 0s;\n}\n\n.perspective-left:hover {\n  transform: perspective(3000px) rotateY(5deg);\n}\n\n.perspective-right {\n  transform: perspective(1500px) rotateY(-15deg);\n  transition: transform 1s ease 0s;\n}\n\n.perspective-right:hover {\n  transform: perspective(3000px) rotateY(-5deg);\n}\n", "demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      Perspective transform on hover\r\n    </h1>\r\n    <div class=\"card-container\">\r\n      <div class=\"image-card perspective-left\"></div>\r\n      <div class=\"image-card perspective-right\"></div>\r\n    </div>\r\n\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n"}', '{}', '{"original_path": "Vanilla/Prsnt/Animation/perspective-transform-on-hover"}'), ('"pulse-loader"', '"Prsnt"', '"vanilla"', '{"demo.css": ".ripple-loader {\n  position: relative;\n  width: 64px;\n  height: 64px;\n}\n\n.ripple-loader div {\n  position: absolute;\n  border: 4px solid #454ADE;\n  border-radius: 50%;\n  animation: ripple-loader 1s ease-out infinite;\n}\n\n.ripple-loader div:nth-child(2) {\n  animation-delay: -0.5s;\n}\n\n@keyframes ripple-loader {\n  0% {\n    top: 32px;\n    left: 32px;\n    width: 0;\n    height: 0;\n    opacity: 1;\n  }\n  100% {\n    top: 0;\n    left: 0;\n    width: 64px;\n    height: 64px;\n    opacity: 0;\n  }\n}\n", "demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      Pulse loader\r\n    </h1>\r\n    <div class=\"ripple-loader\">\r\n      <div></div>\r\n      <div></div>\r\n    </div>\r\n\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n"}', '{}', '{"original_path": "Vanilla/Prsnt/Animation/pulse-loader"}'), ('"rotating-card"', '"Prsnt"', '"vanilla"', '{"demo.css": ".card {\n  perspective: 150rem;\n  position: relative;\n  height: 40rem;\n  max-width: 400px;\n  margin: 2rem;\n  box-shadow: none;\n  background: none;\n}\n\n.card-side {\n  height: 35rem;\n  border-radius: 15px;\n  transition: all 0.8s ease;\n  backface-visibility: hidden;\n  position: absolute;\n  top: 0;\n  left: 0;\n  width: 80%;\n  padding: 2rem;\n  color: white;\n}\n\n.card-side.back {\n  transform: rotateY(-180deg);\n  background-color: #4158D0;\n  background-image: linear-gradient(43deg, #4158D0 0%,#C850C0 46%, #FFCC70 100%);\n}\n\n.card-side.front {\n  background-color: #0093E9;\n  background-image: linear-gradient(160deg, #0093E9 0%, #80D0C7 100%);\n}\n\n.card:hover .card-side.front {\n  transform: rotateY(180deg);\n}\n\n.card:hover .card-side.back {\n  transform: rotateY(0deg);\n}\n", "demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      Rotating Card\r\n    </h1>\r\n    <div class=\"card\">\r\n      <div class=\"card-side front\">\r\n        <div>Front Side</div>\r\n      </div>\r\n      <div class=\"card-side back\">\r\n        <div>Back Side</div>\r\n      </div>\r\n    </div>\r\n\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n"}', '{}', '{"original_path": "Vanilla/Prsnt/Animation/rotating-card"}'), ('"shake-on-invalid-input"', '"Prsnt"', '"vanilla"', '{"demo.css": "@keyframes shake {\n  0% {\n    margin-left: 0rem;\n  }\n  25% {\n    margin-left: 0.5rem;\n  }\n  75% {\n    margin-left: -0.5rem;\n  }\n  100% {\n    margin-left: 0rem;\n  }\n}\n\ninput:invalid {\n  animation: shake 0.2s ease-in-out 0s 2;\n  box-shadow: 0 0 0.6rem #ff0000;\n}\n", "demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      Shake on invalid input\r\n    </h1>\r\n    <input type=\"text\" placeholder=\"Letters only\" pattern=\"[A-Za-z]*\" />\r\n\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n"}', '{}', '{"original_path": "Vanilla/Prsnt/Animation/shake-on-invalid-input"}'), ('"squiggle-link-hover-effect"', '"Prsnt"', '"vanilla"', '{"demo.css": "a.squiggle {\n  background: linear-gradient(to bottom, #0087ca 0%, #0087ca 100%);\n  background-position: 0 100%;\n  background-repeat: repeat-x;\n  background-size: 2px 2px;\n  color: inherit;\n  text-decoration: none;\n}\n\na.squiggle:hover {\n  background-image: url(\"data:image/svg+xml;charset=utf8,%3Csvg xmlns=''http://www.w3.org/2000/svg'' viewBox=''0 0 20 4''%3E%3Cstyle type=''text/css''%3E.squiggle{animation:shift .3s linear infinite;}@keyframes shift {from {transform:translateX(0);}to {transform:translateX(-15px);}}%3C/style%3E%3Cpath fill=''none'' stroke=''%230087ca'' stroke-width=''2'' class=''squiggle'' d=''M0,3.5 c 5,0,5,-3,10,-3 s 5,3,10,3 c 5,0,5,-3,10,-3 s 5,3,10,3''/%3E%3C/svg%3E\");\n  background-size: auto 4px;\n}\n", "demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      Squiggle link hover effect\r\n    </h1>\r\n    <p>\r\n      The <a class=\"squiggle\" href=\"#\">magnificent octopus</a> swam along\r\n      gracefully.\r\n    </p>\r\n\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n"}', '{}', '{"original_path": "Vanilla/Prsnt/Animation/squiggle-link-hover-effect"}'), ('"staggered-animation"', '"Prsnt"', '"vanilla"', '{"demo.css": ".container {\n  overflow-x: hidden;\n  width: 100%;\n}\n\n.menu-toggler {\n  display: none;\n}\n\n.menu-toggler-label {\n  cursor: pointer;\n  font-size: 20px;\n  font-weight: bold;\n}\n\n.stagger-menu {\n  list-style-type: none;\n  margin: 16px 0;\n  padding: 0;\n}\n\n.stagger-menu li {\n  margin-bottom: 8px;\n  font-size: 18px;\n  opacity: 0;\n  transform: translateX(100%);\n  transition-property: opacity, transform;\n  transition-duration: 0.3s;\n  transition-timing-function: cubic-bezier(0.750, -0.015, 0.565, 1.055);\n}\n\n.menu-toggler:checked ~ .stagger-menu li {\n  opacity: 1;\n  transform: translateX(0);\n  transition-delay: calc(0.055s * var(--i));\n}\n", "demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      Static Template\r\n    </h1>\r\n    <div class=\"container\">\r\n      <input type=\"checkbox\" name=\"menu\" id=\"menu\" class=\"menu-toggler\" />\r\n      <label for=\"menu\" class=\"menu-toggler-label\">Menu</label>\r\n      <ul class=\"stagger-menu\">\r\n        <li style=\"--i: 0;\">Home</li>\r\n        <li style=\"--i: 1;\">Pricing</li>\r\n        <li style=\"--i: 2;\">Account</li>\r\n        <li style=\"--i: 3;\">Support</li>\r\n        <li style=\"--i: 4;\">About</li>\r\n      </ul>\r\n    </div>\r\n\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n"}', '{}', '{"original_path": "Vanilla/Prsnt/Animation/staggered-animation"}'), ('"typographic-scale-basics"', '"Prsnt"', '"vanilla"', '{"demo.css": ":root {\r\n  --font-family: \"Roboto\", sans-serif;\r\n  --font-size: 18px;\r\n  --font-weight: 300;\r\n  --line-height: 1.618;\r\n}\r\n\r\n* {\r\n  font-family: var(--font-family);\r\n  font-size: var(--font-size);\r\n  font-weight: var(--font-weight);\r\n  line-height: var(--line-height);\r\n}\r\n\r\n.sub-heading {\r\n  --font-size: 1.618rem;\r\n  --font-weight: 600;\r\n}\r\n\r\n.heading {\r\n  --font-size: 2.618rem;\r\n  --font-weight: 400;\r\n}\r\n\r\n.large-heading {\r\n  --font-size: 4.236rem;\r\n  --font-weight: 500;\r\n}\r\n\r\n.footnote {\r\n  --font-size: 0.618rem;\r\n  --font-weight: 500;\r\n}\r\n", "demo.html": "<!DOCTYPE html>\n<html lang=\"en\">\n  <head>\n    <meta charset=\"UTF-8\" />\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\n    <link rel=\"stylesheet\" href=\"style.css\" />\n    <title>Static Template</title>\n  </head>\n  <body>\n    <h1 class=\"large-heading\">\n      Large Heading\n    </h1>\n    <h2 class=\"heading\">\n      Heading\n    </h2>\n    <h3 class=\"sub-heading\">\n      Sub Heading\n    </h3>\n\n    <script src=\"script.js\"></script>\n  </body>\n</html>\n"}', '{}', '{"original_path": "Vanilla/Prsnt/Animation/typographic-scale-basics"}');